module top_module(
  input            clk_dst,      
  input            rst_dst,      
  input            signal_src,   
  output reg       signal_dst    
);reg           unused_signal_meta;     









  always @(posedge clk_dst)
  begin
    if (rst_dst)
    begin
      unused_signal_meta <= 1'b0;
      signal_dst  <= 1'b0;
    end
    else 
    begin
      unused_signal_meta <= signal_src;
      signal_dst  <= unused_signal_meta;
    end 
  end 

endmodule
